    ['The Man in Black'] = {
        id = 212,
        start_npc = 'Masad',
        start_zone = 'Western Adoulin',
        start_pos = nil,
        description = 'Mission Orders: Rumor has it that Teodor can be found at the Mummers\' Coalition\'s gaming tables. Head there for a brief chat and to let off some steam.',
        reward = nil,
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Clear Skies'},
        next = {'To the Victor...'},
        requirements = nil,
        walkthrough = '1. Go to the Mummers\' Coalition in Western Adoulin and speak to Masad for a cutscene with Teodor.\n2. Beat him at the minigame: Boom or Bust to continue.\n   - To win, you must win 3 rounds.\n3. If you lose, talk to Masad twice in a row to try again.\n::{| class="wikitable"\n4. Each round is played by either "shooting", "staying", using a trick, or folding.\n5. Shooting increases your roll in the same manner that a Corsair\'s Phantom Roll works.\n   - Just like with Corsair\'s rolls, getting more than 11 total will cause you to "bust", and thus lose the round.\n6. Staying closes the round for you.\n   - Either play may stay while the other player may continue.\n   - When both players stay, the round ends and whoever has the highest number closest to 11 wins.\n7. Using a trick does one of three things:\n   - You may only use one trick per round.\n   - Peeking lets you look at one roll of the opponent.\n   - Swapping lets you change one of your rolls for one of the opponent\'s.\n   - Crooked cards forces your opponent to reroll a roll of your choice.\n8. Folding ends the round in a loss.',
        notes = nil,
    },
